output.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT(SUM(?games) AS ?totalNumberOfGames) WHERE {
  VALUES ?year {
    1977 1978 2008 2009
  }
  ?series wdt:P361 wd:Q1967906 ; wdt:P3450 ?year ; wdt:P710 wd:Q334634 ; wdt:P710 wd:Q650840 ; wdt:P1350 ?games .
}
GROUP BY ?totalNumberOfGames

args.sparql:
SELECT (SUM(?games) AS ?totalNumberOfGames) WHERE {
  VALUES ?year {1977 1978 2008 2009}
  ?series wdt:P361 wd:Q1967906 ; # Instance of National League Championship Series
          wdt:P3450 ?year ;
          wdt:P710 wd:Q334634 ; # Los Angeles Dodgers participant
          wdt:P710 wd:Q650840 ; # Philadelphia Phillies participant
          wdt:P1350 ?games .
}
GROUP BY ?totalNumberOfGames
